const msg = $json.message;

// 1. Check that this is a text message
if (!msg?.text) {
  throw new Error('SKIP: not a text message');
}

const text = msg.text.trim();

// 2. Check minimum length
if (text.length < 5) {
  throw new Error('SKIP: message too short');
}

// 3. Whitelist chat_id — only you can trigger the agent
const ALLOWED_CHAT_IDS = [
  YOUR_TELEGRAM_CHAT_ID  // ← replace with your real Telegram chat_id
];

if (!ALLOWED_CHAT_IDS.includes(msg.chat.id)) {
  throw new Error(`SKIP: unauthorized chat_id ${msg.chat.id}`);
}

// 4. Stop commands
const SKIP_COMMANDS = ['/start', '/help', '/status', '/stop'];
if (SKIP_COMMANDS.includes(text.toLowerCase())) {
  throw new Error('SKIP: command, not a search query');
}

// 5. All good — collect data
return {
  query: text,
  research_query: `${text} official website email linkedin contacts company`,
  chat_id: msg.chat.id,
  triggered_at: new Date().toISOString()
};

