const content = $json.output?.[0]?.content?.[0]?.text;

let data;
if (typeof content === 'object' && content !== null) {
  data = content;
} else if (typeof content === 'string') {
  try {
    data = JSON.parse(content.replace(/```json|```/g, '').trim());
  } catch(e) {
    data = {};
  }
} else {
  data = {};
}

return {
  company_name: data?.company_name || "Not found",
  industry:     data?.industry     || "Not found",
  email:        data?.email        || "Not found",
  linkedin:     data?.linkedin     || "Not found",
  phone:        $('Set Company Fields').item.json.phone   || "Not found",
  website:      $('Set Company Fields').item.json.website || "Not found",
  address:      $('Set Company Fields').item.json.address || "Not found",
  automation_opportunities: Array.isArray(data?.automation_opportunities)
    ? data.automation_opportunities : [],
  icebreaker: data?.icebreaker || "Not found"
};

// In "Each Item" mode we work directly with the $json object
const data = $json;
let quality = 0;

// 1. Check Email: exists, not "Not found", and contains @
if (data.email && data.email !== 'Not found' && data.email.includes('@')) {
  quality += 50;
}

// 2. Check LinkedIn: profile URL exists and contains linkedin.com
if (data.linkedin && data.linkedin !== 'Not found' && data.linkedin.includes('linkedin.com')) {
  quality += 50;
}

// Add contact quality score field (0 to 100)
data.contact_quality = quality;

return data;

const data = $json;
let score = 0;
const reasons = [];

// 1. Email (0-40 points) — most important signal
if (data.email && data.email !== 'Not found' && data.email.includes('@')) {
  const isPersonal = /gmail|yahoo|hotmail|outlook\.com/.test(data.email);
  score += isPersonal ? 20 : 40;
  reasons.push(isPersonal ? 'personal email (+20)' : 'corporate email (+40)');
}

// 2. LinkedIn (0-25 points)
if (data.linkedin && data.linkedin !== 'Not found' && data.linkedin.includes('linkedin.com')) {
  score += 25;
  reasons.push('linkedin found (+25)');
}

// 3. Website (0-15 points)
if (data.website && data.website !== 'Not found') {
  score += 15;
  reasons.push('website found (+15)');
}

// 4. Phone (0-10 points)
if (data.phone && data.phone !== 'Not found') {
  score += 10;
  reasons.push('phone found (+10)');
}

// 5. Icebreaker quality (0-10 points)
if (data.icebreaker && data.icebreaker !== 'Not found' && data.icebreaker.length > 50) {
  score += 10;
  reasons.push('quality icebreaker (+10)');
}

data.lead_score = score;
data.score_breakdown = reasons.join(', ');

if (score >= 75)      data.lead_tier = "🔥🔥🔥 HOT";
else if (score >= 55) data.lead_tier = "⭐⭐ WARM";
else if (score >= 30) data.lead_tier = "🌡️ LUKEWARM";
else                  data.lead_tier = "❄️ COLD";

return data;

const response = $json;
const places = response.places || [];
const nextPageToken = response.nextPageToken || null;

return {
  places: places,
  nextPageToken: nextPageToken,
  hasNextPage: !!nextPageToken
};
